import React, { useState } from 'react';
import './Login.css';

function Login({ onLogin }) {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    // BUG: No client-side validation (intentional)
    setIsLoading(true);
    try {
      await onLogin({ username, password });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="login-container">
      <div className="login-card">
        <h2>Login</h2>
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label htmlFor="username">Username</label>
            <input
              type="text"
              id="username"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              placeholder="Enter your username"
              disabled={isLoading}
            />
          </div>

          <div className="form-group">
            <label htmlFor="password">Password</label>
            <input
              type="password"
              id="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Enter your password"
              disabled={isLoading}
            />
          </div>

          <button type="submit" disabled={isLoading}>
            {isLoading ? 'Logging in...' : 'Login'}
          </button>
        </form>

        {/* Testing credentials - BUG: Showing test credentials in production */}
        <div className="test-credentials">
          <h4>Test Credentials:</h4>
          <p><strong>Enabled User:</strong><br /> testuser / password123</p>
          <p><strong>Disabled User:</strong><br /> disableduser / password123</p>
          <p><strong>Admin:</strong><br /> admin / admin123</p>
        </div>
      </div>
    </div>
  );
}

export default Login;
